export function getIdeas(): Idea[] {
  return R.map((r) => {
    const pd = P[r[6]];
    return {
      name: r[0],
      country: r[1],
      type: TYPES[r[2]],
      difficulty: DIFFS[r[3]],
      category: CATS[r[4]],
      source: r[5] ? "todoist" : "newsletter",
      description: r[7] || "",
      cost: pd.c,
      revenueModel: pd.r,
      plan: pd.s,
    };
  });
}
